#include &lt;unistd.h&gt;
#include &lt;stdio.h&gt;

void spawn_workers() {
    for (int i = 0; i < 4; i++) {
        pid_t pid = fork();

        if (pid == 0) {
            printf("Worker %d executing.\n", i);
            // DANGER: The child does not exit after its work!
        }
    }
}

#include &lt;stdio.h&gt;
#include &lt;unistd.h&gt;
#include &lt;stdlib.h&gt;

extern char **environ; // Global environment pointer passed by OS

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        perror("Fork failed");
        exit(1);
    }

    if (pid == 0) {
        // CHILD PROCESS
        // We set up the arguments exactly as the command line would.
        // Note: argv[0] must be the program name, and it MUST end in NULL.
        char *args[] = {"ls", "-la", NULL};

        // Replace the child's memory image with the 'ls' binary.
        execve("/bin/ls", args, environ);

        // If execve() succeeds, this line is mathematically unreachable.
        // If we hit this line, execve() failed (e.g., path not found).
        perror("Execve failed");
        exit(1);
    } else {
        // PARENT PROCESS
        // The parent continues executing its own code.
        printf("Spawned child %d to run ls.\n", pid);

        // (In Day 26, we will learn how to wait() for this child to finish)
    }

    return 0;
}
